import React from "react";
import { motion } from "framer-motion";
import { ReactComponent as LanternSVG } from "../public/light14.svg"; // นำเข้า SVG

const Home = () => {
  return (
    <div className="background-gradient h-screen flex flex-col justify-center items-center text-center">

      {/* ✅ SVG ที่แยกชิ้นส่วนได้ */}
      <div className="lantern-container">
        <LanternSVG className="lantern-svg" />

        {/* ✅ ขยับเฉพาะโคมไฟแต่ละลูก */}
        <motion.div
          className="lantern lantern1"
          animate={{ rotate: [-5, 5, -5], y: [0, 10, 0] }}
          transition={{ duration: 2, repeat: Infinity, ease: "easeInOut" }}
        />

        <motion.div
          className="lantern lantern2"
          animate={{ rotate: [5, -5, 5], y: [5, 0, 5] }}
          transition={{ duration: 2.5, repeat: Infinity, ease: "easeInOut" }}
        />
      </div>
    </div>
  );
};

export default Home;
